#include<stdio.h>
typedef long long int ll;
void print(int *a,int n)
{
    int i;
    for(i=0;i<n;i++)
        printf("%d ",a[i]);
    printf("\n");
}
int gcd(int a,int b)
{
    int r;
    while(b!=0)
    {
        r=a%b;
        a=b;
        b=r;
    }
    return a;
}
int u[1000005]={0},v[1000005]={0};
int st,l,m;
void mark(int *a,ll x,ll y,ll h)
{
    int t=2;
    a[h]=1;
    while(1)
    {
        h=((x*h)+y)%m;
        if(a[h]!=0)
        {
            a[st]=a[h];
            a[l]=t-a[h];
            break;
        }
        a[h]=t;
        t++;
    }
}
int main()
{
    st=1000003;
    l=1000004;
    ll x1,y1,h1,x2,y2,h2,a1,a2,k,r,d,i,t,a,b;
    ll t1,t2;
    scanf("%d",&m);
    scanf("%lld %lld",&h1,&a1);
    scanf("%lld %lld",&x1,&y1);
    scanf("%lld %lld",&h2,&a2);
    scanf("%lld %lld",&x2,&y2);
    mark(u,x1,y1,h1);
    mark(v,x2,y2,h2);
    t1=-1;t2=-1;
    if(u[a1]>0 && v[a2]>0)
    {
        if(u[a1]==v[a2])
        {
            printf("%d\n",u[a1]-1);
            return 0;
        }
        if((u[a1]>=u[st]) && (v[a2]>=u[a1] && (v[a2]-u[a1])%u[l]==0)){
            printf("%d\n",v[a2]-1);
            return 0;   }
        else if(v[a2]>=v[st] && (u[a1]>=v[a2] && (u[a1]-v[a2])%v[l]==0)){
            printf("%d\n",u[a1]-1); 
            return 0;
        }
        else if((u[a1]>=u[st] && v[a2]>=v[st]))
        {
            t1=gcd(u[l],v[l]);
            t2=u[a1]-v[a2];
            if(t2<0)
                t2=-t2;
            if(t2%t1!=0)
            {
                printf("-1\n");
                return 0;
            }
            a=u[a1]-1;
            b=v[a2]-1;
            while(a!=b)
            {
                if(a<b)
                    a+=u[l];
                else
                    b+=v[l];    

            }
            printf("%lld\n",a); 
            return 0;
        }
    }
    printf("-1\n");
    return 0;
}

